 console.log("●● expand.js");
	
 var selectors = {
     /* Selectors for the nodes that will contain an expand/collapse button. */
     "expand_buttons":[
     /* Table caption */
     /* "table > caption", */
     /* Article title */
     ".topic > .title",
     /* Section title. Exclude task labels generated by DITA-OT (EXM-37958 & EXM-38501).*/
     ".sectiontitle:not(.tasklabel)",
     /* Index terms groups */
     ".wh_term_group > .wh_first_letter"]
 };
 
 
     //   Add expand-collapse support.
 function preloadElements() {
     // 强制预加载所有图片（包括折叠区域内的）
     $('img[data-src], .carousel-inner img, .fig.carousel img').each(function() {
         const targetSrc = $(this).data('src') || $(this).attr('src');
         if (!targetSrc) return;
 
         // 关键：直接替换 src，绕过父级隐藏限制
         $(this).attr('src', targetSrc);
         
         // 虚拟加载兜底（兼容性）
         new Image().src = targetSrc;
     });
 }
     $(document).ready(function () { 
      /* Add the expand/collapse buttons. */
      selectors.expand_buttons.forEach(
      function (selector) {
          var matchedNodes = $(document).find(selector);
          // Add the expand/collapse support only if the title node has visible siblings.
          var visibleSiblings = matchedNodes.siblings(':not(:hidden)');// 所有不隐藏的兄弟
          if (visibleSiblings.length > 0) {
              // Add the element with expand/collapse capabilities
              matchedNodes.prepend("<span class=\"wh_expand_btn expanded\"/>");
              markHiddenSiblingsAsNotExpandable(matchedNodes);
          }
      });
     
     // 定义 mobileExpandHandler 处理函数
     function mobileExpandHandler(event) {
         var currentBtn = $(this);
         
         // 切换按钮状态及内容
         $(this).toggleClass("expanded");
         var siblings = $(this).parent().siblings(':not(.wh_not_expandable)');
         var tagName = $(this).parent().prop("tagName");
         if (tagName === "CAPTION") {
             siblings.toggle();
         } else {
             siblings.slideToggle(500);
         }
         
         // 预加载图片
         if ($(this).hasClass("expanded")) {
             siblings.find('img[data-src]').each(function () {
                 const targetSrc = $(this).data('src');
                 if (targetSrc) {
                     $(this).attr('src', targetSrc);
                     new Image().src = targetSrc; // 虚拟加载
                 }
             });
         }
         
         // 移动端逻辑：展开一个时关闭其他已展开的内容
         if ($(window).width() < 768) {
             var parentButtons = $(); // 存储需要保持展开的父级按钮
     
             // 检查当前按钮的标题级别
             var titleElement = currentBtn.closest('h2.title, h3.title, h4.title, h5.title, h3.sectiontitle, h4.title.sectiontitle');
             if (titleElement.length) {
                 var titleTag = titleElement.prop('tagName');
                 var titleClasses = titleElement.attr('class') || '';
                 
                 console.log('DEBUG 标题元素:', titleTag, '类:', titleClasses);
                 
                 // 对于H3,H4,H5，需要确保父级标题保持展开
                 if (titleTag !== 'H2' || titleClasses.includes('sectiontitle')) {
                     // 特殊处理section中的标题
                     if (titleClasses.includes('sectiontitle')) {
                         // 对于section中的标题，查找最近的.topic父容器中的标题按钮
                         var parentTopic = titleElement.closest('.topic');
                         if (parentTopic.length) {
                             var parentTitleBtn = parentTopic.find('> .title .wh_expand_btn');
                             if (parentTitleBtn.length) {
                                 parentButtons = parentButtons.add(parentTitleBtn);
                             }
                             
                             // 特别处理H4 sectiontitle，确保其直接父级topic的标题展开
                             if ((titleTag === 'H4' || titleTag === 'H3') && titleClasses.includes('sectiontitle')) {
                                 var sectionParent = titleElement.closest('.section');
                                 if (sectionParent.length) {
                                     var sectionParentTopic = sectionParent.closest('.topic');
                                     if (sectionParentTopic.length) {
                                         var sectionParentTitleBtn = sectionParentTopic.find('> .title .wh_expand_btn');
                                         if (sectionParentTitleBtn.length) {
                                             parentButtons = parentButtons.add(sectionParentTitleBtn);
                                         }
                                         
                                         // 还需要确保sectionParentTopic的父级也展开
                                         sectionParentTopic.parents('.topic').each(function() {
                                             var ancestorTitleBtn = $(this).find('> .title .wh_expand_btn');
                                             if (ancestorTitleBtn.length) {
                                                 parentButtons = parentButtons.add(ancestorTitleBtn);
                                             }
                                         });
                                     }
                                 }
                             }
                         }
                     } else {
                         // 对于普通的topic标题，查找所有父级topic中的标题按钮
                         titleElement.closest('.topic').parents('.topic').each(function() {
                             var parentTitleBtn = $(this).find('> .title .wh_expand_btn');
                             if (parentTitleBtn.length) {
                                 parentButtons = parentButtons.add(parentTitleBtn);
                             }
                         });
                     }
                 }
                 
                 // 特别处理H3标题 - 确保父级H2展开
                 if (titleTag === 'H3') {
                     var parentTopic = titleElement.closest('.topic');
                     if (parentTopic.length) {
                         var parentH2Btn = parentTopic.find('> h2.title .wh_expand_btn');
                         if (parentH2Btn.length) {
                             parentButtons = parentButtons.add(parentH2Btn);
                         }
                     }
                 }
             }
     
             console.log('DEBUG 需要保持展开的父级按钮数量:', parentButtons.length);
             
             // 排除当前按钮和父级按钮，收起其他所有展开的内容
             var excludeBtns = currentBtn.add(parentButtons);
             $('.wh_expand_btn.expanded').not(excludeBtns).each(function() {
                 console.log('DEBUG 收起按钮:', $(this).closest('h2, h3, h4').prop('tagName'));
                 $(this).removeClass("expanded");
                 $(this).parent().siblings(':not(.wh_not_expandable)').slideUp(500);
             });
             
             // 确保父级按钮都处于展开状态
             parentButtons.each(function() {
                 if (!$(this).hasClass('expanded')) {
                     console.log('DEBUG 展开父级按钮:', $(this).closest('h2, h3, h4').prop('tagName'));
                     $(this).addClass('expanded');
                     $(this).parent().siblings(':not(.wh_not_expandable)').slideDown(500);
                     
                     // 预加载父级内容中的图片
                     $(this).parent().siblings(':not(.wh_not_expandable)').find('img[data-src]').each(function () {
                         const targetSrc = $(this).data('src');
                         if (targetSrc) {
                             $(this).attr('src', targetSrc);
                             new Image().src = targetSrc; // 虚拟加载
                         }
                     });
                 }
             });
             
             // 视口补偿 - 滚动到当前展开的元素
             setTimeout(function() {
                 var currentTitle = currentBtn.closest('h2, h3, h4');
                 if (currentTitle.length && currentBtn.hasClass('expanded')) {
                     var offsetTop = currentTitle.offset().top;
                     var targetPosition = Math.max(0, offsetTop - 10); // 减去10像素确保完全可见，但不低于0
                     
                     console.log('DEBUG 视口补偿滚动到:', targetPosition);
                     $('html, body').animate({
                         scrollTop: targetPosition
                     }, 300);
                 }
             }, 400);
         }
         
         event.stopImmediatePropagation();
         return false;
     }
         
     
     // 绑定点击事件 - 统一使用mobileExpandHandler处理所有情况
     $(document).find('.wh_expand_btn').click(mobileExpandHandler);
     
     // 标题点击事件 - 触发对应的按钮点击
     $(document).find('h2.title, h3.title, h4.title, h5.title, h3.sectiontitle, h4.title.sectiontitle').click(function (event) {
         var expandBtn = $(this).find('.wh_expand_btn');
         if (expandBtn.length > 0) {
             expandBtn.click();
         }
         event.stopImmediatePropagation();
         return false;
     });
     
     // 移动端初始化逻辑
     if ($(window).width() < 768) {
         $('.wh_expand_btn').each(function () {
             var siblings = $(this).parent().siblings(':not(.wh_not_expandable)');

             // 确保懒加载资源加载
             siblings.find('img[data-src]').each(function () {
                 $(this).attr('src', $(this).data('src')); // Replace data-src with src
             });

             // 默认移除 expanded 状态
             $(this).removeClass('expanded');

             // 隐藏内容
             siblings.hide();
         });
     }
     
     
     });
 
 /**
  * Marks the hidden siblings of the matched nodes as being not expandable.
  *
  * @param nodes The matched nodes.
  */
 function markHiddenSiblingsAsNotExpandable(nodes) {
     var siblings = nodes.siblings(":hidden");// 所有隐藏的兄弟
     siblings.addClass("wh_not_expandable");
 }
 
